    StringTokenizer st = new StringTokenizer(br.readLine(), " ");

    st.nextToken();
    int bagSize = Integer.parseInt(st.nextToken());
    int sum = 0;
    int left = 1;
    int right = bagSize;
    int appleDropCount = Integer.parseInt(br.readLine());

    for (int i = 0; i < appleDropCount; i++) {
      int where = Integer.parseInt(br.readLine());

      if (left <= where && right >= where) continue;
      else if (left > where) {
        sum += left - where;
        right -= left - where;
        left = where;
      } else {
        sum += where - right;
        left += where - right;
        right = where;
      }

    }

    System.out.println(sum);
  }

}

class Pair {
  public int x, y;
  public Pair(int x, int y) {
    this.x = x;
    this.y = y;
  }
  int getX() { return x; }
  int getY() { return y; }
}

public class Main {

  public static void main(String[] args) throws IOException {

    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    StringTokenizer st = new StringTokenizer(br.readLine(), " ");
    Queue<Pair> q = new LinkedList<>();

    int h = parseInt(st.nextToken());
    int w = parseInt(st.nextToken());
    int[][] canvas = new int[h][w];

    for (int i = 0; i < h; i++) {
      st = new StringTokenizer(br.readLine(), " ");
      for (int j = 0; j < w; j++)
        canvas[i][j] = parseInt(st.nextToken());
    }

    boolean[][] visited = new boolean[h][w];
    int paintCount = 0;
    int area = 0;
    int max = 0;
    int[] dx = { 0, 0, -1, 1 };
    int[] dy = { -1, 1, 0, 0 };

    for (int i = 0; i < h; i++) {
      for (int j = 0; j < w; j++) {
        if (canvas[i][j] == 0 || visited[i][j]) continue;
        paintCount++;
        q.offer(new Pair(i, j));
        visited[i][j] = true;
        area = 0;
        while (!q.isEmpty()) {
          Pair p = q.poll();
          area++;
          for (int k = 0; k < 4; k++) {
            int x = p.x + dx[k];
            int y = p.y + dy[k];
            if (x < 0 || x >= h || y < 0 || y >= w)
              continue;
            if (canvas[x][y] == 1 && !visited[x][y]) {
              q.offer(new Pair(x, y));
              visited[x][y] = true;
            }
          }
        }
        if (area > max) max = area;
      }
    }

    System.out.println(paintCount);
    System.out.println(max);
  }

}

